(async () => {

  const isPromotion = (article) => {
    if (!article) return false;

    // 明示的な aria-label による判定（英語/日本語）
    if (article.querySelector('[aria-label*="Promoted"], [aria-label*="プロモ"], [aria-label*="広告"]')) return true;

    // 記事内の短いラベル類に "Promoted" / "Promoted by" / "プロモーション" / "広告" が含まれるか
    // ※ placementTracking 等の埋め込み要素は判定から除外する（動画誤判定を防ぐ）
    const labelCandidates = Array.from(article.querySelectorAll('div,span,small')).slice(0, 50);
    for (const el of labelCandidates) {
      const txt = (el.textContent || '').trim();
      if (!txt) continue;
      if (/Promoted by/i.test(txt)) return true;
      if (txt === 'Promoted' || txt === 'プロモーション' || txt === '広告') return true;
    }

    return false;
  };

  const sleep = (ms) => new Promise(r => setTimeout(r, ms));

  const tweets = Array.from(document.querySelectorAll('article[data-testid="tweet"]'));
  for (let i = 0; i < tweets.length; i += 1) {
    const article = tweets[i];

    if (isPromotion(article)) continue;

    let like = article.querySelector('button[data-testid="like"]');
    if (!like) continue;

    const pressed = like.getAttribute('aria-pressed');
    if (pressed === 'true') continue;

    try {
      like.scrollIntoView({ block: 'center' });
      like.click();

      const deadline = Date.now() + 1200;
      while (Date.now() < deadline) {
        // ★ いいね/取り消しボタンを正しく見る
        const unlike = article.querySelector('button[data-testid="unlike"]');
        like = article.querySelector('button[data-testid="like"]') || like;

        const likePressed = like?.getAttribute('aria-pressed');
        if (unlike || likePressed === 'true') {
          return { didAction: true, index: i };
        }

        // ★ UI更新に時間を与える
        await sleep(50);
      }

      return { didAction: false, reason: 'like-not-confirmed', index: i };
    } catch (err) {
      return { didAction: false, reason: err && err.message ? err.message : String(err), index: i };
    }
  }
  return { didAction: false, reason: 'no-unliked-found' };
})();
